import { FC } from 'react';

import { PRODUCT_COMPARISON_RESET } from '../ProductComparison.constants';

import {
  COMPARE_BUTTON_LABEL,
  MAX_SELECTED_ITEMS,
  MIN_SELECTED_ITEMS,
  RESET_BUTTON_LABEL,
  COMPARE_BUTTON_TESTID,
  RESET_BUTTON_TESTID,
  STATUS_TESTID,
} from './ControlBar.constants';
import {
  Buttons,
  Card,
  Cards,
  ClearButton,
  CompareButton,
  Image,
  Status,
  Text,
  TextContainer,
  Wrapper,
} from './ControlBar.styles';
import { ControlBarProps } from './ControlBar.types';

const ControlBar: FC<ControlBarProps> = ({
  clearItems,
  items,
  showProductModal,
}) => {
  return (
    <Wrapper>
      <Cards>
        {items.map((item) => (
          <Card key={item.id}>
            <Image>{item.image}</Image>
            <TextContainer>
              <Text>{item.title}</Text>
            </TextContainer>
          </Card>
        ))}
      </Cards>
      <Buttons>
        <ClearButton
          id={PRODUCT_COMPARISON_RESET}
          data-testid={RESET_BUTTON_TESTID}
          disabled={items.length === 0}
          onClick={clearItems}
        >
          {RESET_BUTTON_LABEL}
        </ClearButton>
        <CompareButton
          data-testid={COMPARE_BUTTON_TESTID}
          disabled={items.length < MIN_SELECTED_ITEMS}
          onClick={showProductModal}
        >
          {COMPARE_BUTTON_LABEL}
          <Status data-testid={STATUS_TESTID}>
            ({items.length}/{MAX_SELECTED_ITEMS})
          </Status>
        </CompareButton>
      </Buttons>
    </Wrapper>
  );
};
export default ControlBar;
