import { FC } from 'react';

import ControlBar from './ControlBar';
import Modal from './Modal';
import { ProductComparisonProps } from './ProductComparison.types';
import Table from './Table';
import { createSelectedItems } from './helpers/createSelectedItems';

const ProductComparison: FC<ProductComparisonProps> = (props) => {
  const {
    livePrices,
    products,
    returnFocus,
    selectedItemIDs,
    dispatchers,
    showModal,
  } = props;

  const selectedItems = createSelectedItems(selectedItemIDs, products);

  return (
    <>
      <ControlBar
        items={selectedItems}
        clearItems={dispatchers.clearProductSelection}
        showProductModal={dispatchers.showProductModal}
      />
      <Modal
        livePrices={livePrices}
        items={selectedItems}
        isHidden={!showModal}
        returnFocus={returnFocus}
        hideProductModal={dispatchers.hideProductModal}
      >
        <Table livePrices={livePrices} items={selectedItems} />
      </Modal>
    </>
  );
};

export default ProductComparison;
